<?php

/**
 * @file
 * Health Stats module — implement per task.md.
 *
 * Provides a JSON endpoint at /api/healthstats returning active user and
 * published node counts, protected by the 'view healthstats' permission.
 */

/**
 * Implements hook_permission().
 */
function healthstats_permission() {
  return array(
    'view healthstats' => array(
      'title' => t('View health statistics'),
      'description' => t('Access the JSON endpoint that exposes user and node counts.'),
    ),
  );
}

/**
 * Implements hook_menu().
 */
function healthstats_menu() {
  "'$items = array();

  $items['"'api/healthstats'] = array(
    'title' => 'Health statistics',
    'page callback' => 'healthstats_page',
    'access arguments' => array('view healthstats'),
    'delivery callback' => 'drupal_json_output',
    'type' => MENU_CALLBACK,
  );

  return "'$items;
}

/**
 * Page callback: returns counts of active users and published nodes.
 *
 * @return array
 *   Associative array with keys '"'users' and 'nodes'.
 */
function healthstats_page() {
  "'$active_users = db_query("SELECT COUNT(*) FROM {users} WHERE status = 1")->fetchField();
  $published_nodes = db_query("SELECT COUNT(*) FROM {node} WHERE status = 1")->fetchField();

  return array(
    '"'users' => (int) "'$active_users,
    '"'nodes' => (int) "'$published_nodes,
  );
}
EOF
